	@Test
	void sameStatementsWithDifferentLocalValueIdsHaveSameFingerprint() {
		Statement first = statement("urn:subject:a", "urn:predicate:p", "value-a", null);
		Statement second = statement("urn:subject:b", "urn:predicate:p", "value-b", VF.createIRI("urn:context:1"));
		BNode sharedBNode = VF.createBNode("stable-node");
		Statement third = VF.createStatement(sharedBNode, RDFS.LABEL, VF.createLiteral("blank-node"),
				VF.createIRI("urn:context:2"));

		LmdbStore primary = enabledStore(new File(dataDir, "primary"));
		LmdbStore replica = enabledStore(new File(dataDir, "replica"));
		primary.init();
		replica.init();
		try {
			addAll(primary, List.of(first, second, third));
			addAll(replica, List.of(third, second, first));

			LmdbStatementFingerprint primaryFingerprint = primary.getStatementFingerprint();
			LmdbStatementFingerprint replicaFingerprint = replica.getStatementFingerprint();

			assertTrue(primaryFingerprint.isAvailable());
			assertEquals(primaryFingerprint, replicaFingerprint);
			assertEquals(3L, primaryFingerprint.getExplicit().getCount());
			assertEquals(0L, primaryFingerprint.getInferred().getCount());
		} finally {
			replica.shutDown();
			primary.shutDown();
		}
	}

	@Test
	void reusedValueIdDoesNotReusePreviousValueHash() throws Exception {
		IRI predicate = VF.createIRI("urn:predicate:shared");
		Literal object = VF.createLiteral("shared object");
		Statement anchor = VF.createStatement(VF.createIRI("urn:subject:anchor"), predicate, object);
		BNode firstSubject = VF.createBNode("reused-first");
		Statement first = VF.createStatement(firstSubject, predicate, object);
		BNode secondSubject = VF.createBNode("reused-second");
		Statement second = VF.createStatement(secondSubject, predicate, object);
		LmdbStatementFingerprint referenceFingerprint = fingerprintFor(new File(dataDir, "reuse-reference"),
				List.of(anchor, second));

		LmdbStore store = enabledStore(new File(dataDir, "reuse-live"));
		store.init();
		try {
			ValueStore valueStore = valueStore(store);
			addAll(store, List.of(anchor, first));
			long firstSubjectId = valueStore.getId(firstSubject);
			ValueStoreRevision removalRevision = valueStore.getRevision();

			try (RepositoryConnection connection = new SailRepository(store).getConnection()) {
				connection.remove(first);
			}
			forceValueIdEviction(valueStore, removalRevision);

			addAll(store, List.of(second));
			long secondSubjectId = valueStore.getId(secondSubject);
			assertEquals(firstSubjectId, secondSubjectId);

			assertEquals(referenceFingerprint, store.getStatementFingerprint());
			store.rebuildStatementFingerprint();
			assertEquals(referenceFingerprint, store.getStatementFingerprint());
		} finally {
			store.shutDown();
		}
	}

	@Test
	void duplicateAddRollbackAndRemoveUpdateFingerprintOnlyForCommittedStatementSetChanges() {
		Statement first = statement("urn:subject:a", "urn:predicate:p", "value-a", null);
		Statement rolledBack = statement("urn:subject:b", "urn:predicate:p", "value-b", null);
		LmdbStore store = enabledStore(new File(dataDir, "commits"));
		store.init();
		try {
			addAll(store, List.of(first));
			LmdbStatementFingerprint afterAdd = store.getStatementFingerprint();

			addAll(store, List.of(first));
			assertEquals(afterAdd, store.getStatementFingerprint());

			try (RepositoryConnection connection = new SailRepository(store).getConnection()) {
				connection.begin();
				connection.add(rolledBack);
				connection.rollback();
			}
			assertEquals(afterAdd, store.getStatementFingerprint());

			try (RepositoryConnection connection = new SailRepository(store).getConnection()) {
				connection.remove(first);
			}
			LmdbStatementFingerprint afterRemove = store.getStatementFingerprint();
			assertNotEquals(afterAdd, afterRemove);
			assertEquals(0L, afterRemove.getExplicit().getCount());
		} finally {
			store.shutDown();
		}
	}

	@Test
	void inferredAndExplicitStatementsAreTrackedSeparately() {
		IRI subject = VF.createIRI("urn:subject:a");
		IRI predicate = VF.createIRI("urn:predicate:p");
		IRI object = VF.createIRI("urn:object:o");
		LmdbStore store = enabledStore(new File(dataDir, "explicit-inferred"));
		store.init();
		try {
			try (InferencerConnection connection = (InferencerConnection) store.getConnection()) {
				connection.begin();
				connection.addInferredStatement(subject, predicate, object);
				connection.commit();
			}

			LmdbStatementFingerprint afterInferred = store.getStatementFingerprint();
			assertEquals(0L, afterInferred.getExplicit().getCount());
			assertEquals(1L, afterInferred.getInferred().getCount());

			try (RepositoryConnection connection = new SailRepository(store).getConnection()) {
				connection.add(subject, predicate, object);
			}

			LmdbStatementFingerprint afterPromotion = store.getStatementFingerprint();
			assertEquals(1L, afterPromotion.getExplicit().getCount());
			assertEquals(0L, afterPromotion.getInferred().getCount());
		} finally {
			store.shutDown();
		}
	}

