	private static LmdbStore enabledStore(File storeDir) {
		LmdbStoreConfig config = new LmdbStoreConfig("spoc,posc");
		config.setStatementFingerprintEnabled(true);
		return new LmdbStore(storeDir, config);
	}

	private static Statement statement(String subject, String predicate, String label, IRI context) {
		if (context == null) {
			return VF.createStatement(VF.createIRI(subject), VF.createIRI(predicate), VF.createLiteral(label));
		}
		return VF.createStatement(VF.createIRI(subject), VF.createIRI(predicate), VF.createLiteral(label), context);
	}

	private static void addAll(LmdbStore store, List<Statement> statements) {
		try (RepositoryConnection connection = new SailRepository(store).getConnection()) {
			connection.add(statements);
		}
	}

	private static LmdbStatementFingerprint fingerprintFor(File storeDir, List<Statement> statements) {
		LmdbStore store = enabledStore(storeDir);
		store.init();
		try {
			addAll(store, statements);
			return store.getStatementFingerprint();
		} finally {
			store.shutDown();
		}
	}

	private static void forceValueIdEviction(ValueStore valueStore, ValueStoreRevision revision) throws IOException {
		valueStore.unusedRevisionIds.add(revision.getRevisionId());
		valueStore.forceEvictionOfValues();
		valueStore.startTransaction(true);
		valueStore.commit();
	}

	private static TripleStore tripleStore(LmdbStore store) throws Exception {
		Field tripleStoreField = LmdbSailStore.class.getDeclaredField("tripleStore");
		tripleStoreField.setAccessible(true);
		return (TripleStore) tripleStoreField.get(store.getBackingStore());
	}

	private static ValueStore valueStore(LmdbStore store) throws Exception {
		Field valueStoreField = LmdbSailStore.class.getDeclaredField("valueStore");
		valueStoreField.setAccessible(true);
		return (ValueStore) valueStoreField.get(store.getBackingStore());
	}

	private static AtomicBoolean storeTxnStarted(LmdbStore store) throws Exception {
		Field storeTxnStartedField = LmdbSailStore.class.getDeclaredField("storeTxnStarted");
		storeTxnStartedField.setAccessible(true);
		return (AtomicBoolean) storeTxnStartedField.get(store.getBackingStore());
	}

	private static void forceRecordCache(TripleStore store) throws Exception {
		Field recordCacheField = TripleStore.class.getDeclaredField("recordCache");
		recordCacheField.setAccessible(true);
		File cacheDir = new File(dataDir(store), "forced-record-cache");
		assertTrue(cacheDir.mkdirs() || cacheDir.isDirectory());
		recordCacheField.set(store, new TxnRecordCache(cacheDir));
	}

	private static File dataDir(TripleStore store) throws Exception {
		Field dirField = TripleStore.class.getDeclaredField("dir");
		dirField.setAccessible(true);
		return (File) dirField.get(store);
	}

